const Hero = ({ data }) => {
  return (
    <section id="home" className="beranda" aria-label="Brief Introduction">
      <div className="konten-beranda">
        <h1 className="judul-beranda">{data.name}</h1>
        <h2 className="subjudul-beranda">{data.titles.join(" | ")}</h2>
        <p className="slogan-beranda">"{data.tagline}"</p>
        <div className="aksi-beranda">
          <a href="#projects" className="tombol primer">View Portfolio</a>
          <a href={data.linkedin} target="_blank" rel="noreferrer" className="tombol" aria-label="Visit LinkedIn profile">LinkedIn Profile</a>
        </div>
      </div>
    </section>
  );
};

export default Hero;
